 1	import React, { FC } from 'react';
 2	
 3	import { RouteModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { ResourceYAMLEditor, useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 5	import {
 6	  PageSection,
 7	  PageSectionVariants,
 8	  Text,
 9	  TextVariants,
10	  Title,
11	} from '@patternfly/react-core';
12	import { EditorType } from '@utils/components/SyncedEditor/EditorToggle';
13	import { SyncedEditor } from '@utils/components/SyncedEditor/SyncedEditor';
14	import { safeYAMLToJS } from '@utils/components/SyncedEditor/yaml';
15	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
16	import { getValidNamespace } from '@utils/utils';
17	import { LAST_VIEWED_EDITOR_TYPE_USERSETTING_KEY } from '@views/networkpolicies/new/utils/const';
18	
19	import RouteForm from './RouteForm';
20	import { generateDefaultRoute } from './utils';
21	
22	const RouteFormPage: FC = () => {
23	  const { t } = useNetworkingTranslation();
24	
25	  const [activeNamespace] = useActiveNamespace();
26	  const namespace = getValidNamespace(activeNamespace);
27	
28	  const k8sObj = generateDefaultRoute(namespace);
29	
30	  return (
31	    <>
32	      <PageSection variant={PageSectionVariants.light}>
33	        <Title headingLevel="h2">{t('Create {{label}}', { label: RouteModel.label })}</Title>
34	        <Text component={TextVariants.p}>
35	          {t('Routing is a way to make your application publicly visible')}
36	        </Text>
37	      </PageSection>
38	
39	      <SyncedEditor
40	        displayConversionError
41	        FormEditor={RouteForm}
42	        initialData={k8sObj}
43	        initialType={EditorType.Form}
44	        lastViewUserSettingKey={LAST_VIEWED_EDITOR_TYPE_USERSETTING_KEY}
45	        YAMLEditor={({ initialYAML = '', onChange }) => (
46	          <ResourceYAMLEditor
47	            create
48	            hideHeader
49	            initialResource={safeYAMLToJS(initialYAML)}
50	            onChange={onChange}
51	          />
52	        )}
53	      />
54	    </>
55	  );
56	};
57	
58	export default RouteFormPage;

